"""Main entry point for the Library Management System."""from src.collections.book_collection import BookCollectionfrom src.collections.member_collection import MemberCollectionfrom src.collections.loan_collection import LoanCollectionfrom src.ui.menu_system import LibraryMenuSystemfrom src.models.book import Bookfrom src.models.member import Memberdef initialize_sample_data(books, members):    """Seed the system with some starter data for demonstration."""    # Sample books    sample_books = [        Book("The Great Gatsby", "F. Scott Fitzgerald", "978-0743273565", 1925),        Book("To Kill a Mockingbird", "Harper Lee", "978-0446310789", 1960),        Book("1984", "George Orwell", "978-0451524935", 1949),        Book("Clean Code", "Robert C. Martin", "978-0132350884", 2008, is_reference=True),    ]    for book in sample_books:        try:            books.add_book(book)        except ValueError:            pass  # Ignore duplicates if run multiple times    # Sample members    sample_members = [        Member("Alice Johnson", "M001", "alice@email.com", "555-0101"),        Member("Bob Smith", "M002", "bob@email.com", "555-0102"),        Member("Carol Davis", "M003", "carol@email.com", "555-0103"),    ]    for member in sample_members:        try:            members.add_member(member)        except ValueError:            passdef main():    """Initialize and run the application."""    book_collection = BookCollection()    member_collection = MemberCollection()    loan_collection = LoanCollection()    # Load sample data    initialize_sample_data(book_collection, member_collection)    # Start the UI    menu = LibraryMenuSystem(book_collection, member_collection, loan_collection)    menu.run()if __name__ == "__main__":    main()